import java.util.*;

interface EvictionStrategy {
    String selectEviction(Map<String, int[]> metadata);
    String getName();
}

class LRUEviction implements EvictionStrategy {
    public String selectEviction(Map<String, int[]> metadata) {
        return metadata.entrySet().stream()
            .min(Comparator.comparingInt(e -> e.getValue()[1]))
            .map(Map.Entry::getKey).orElse(null);
    }
    public String getName() { return "LRU"; }
}

class LFUEviction implements EvictionStrategy {
    public String selectEviction(Map<String, int[]> metadata) {
        return metadata.entrySet().stream()
            .min(Comparator.comparingInt(e -> e.getValue()[0]))
            .map(Map.Entry::getKey).orElse(null);
    }
    public String getName() { return "LFU"; }
}

class FIFOEviction implements EvictionStrategy {
    public String selectEviction(Map<String, int[]> metadata) {
        return metadata.entrySet().stream()
            .min(Comparator.comparingInt(e -> e.getValue()[2]))
            .map(Map.Entry::getKey).orElse(null);
    }
    public String getName() { return "FIFO"; }
}

class Cache {
    private int maxSize, clock = 0, insertCounter = 0;
    private Map<String, String> store = new HashMap<>();
    // metadata: [frequency, lastAccessed, insertOrder]
    private Map<String, int[]> metadata = new HashMap<>();
    private EvictionStrategy strategy;

    public Cache(int size, EvictionStrategy strategy) {
        this.maxSize = size;
        this.strategy = strategy;
    }
    public String get(String key) {
        if (!store.containsKey(key)) return "MISS";
        int[] meta = metadata.get(key);
        meta[0]++; meta[1] = ++clock;
        return store.get(key);
    }
    public void put(String key, String value) {
        if (store.containsKey(key)) { store.put(key, value); return; }
        if (store.size() >= maxSize) {
            String evict = strategy.selectEviction(metadata);
            System.out.println("  Evicting '" + evict + "' (" + strategy.getName() + ")");
            store.remove(evict); metadata.remove(evict);
        }
        store.put(key, value);
        metadata.put(key, new int[]{1, ++clock, ++insertCounter});
    }
    public void dump() {
        System.out.println("  Cache keys: " + store.keySet());
    }
}

public class Main {
    public static void main(String[] args) {
        System.out.println("=== LRU Cache ===");
        Cache lru = new Cache(3, new LRUEviction());
        lru.put("a", "1"); lru.put("b", "2"); lru.put("c", "3");
        lru.get("a"); // touch 'a' so 'b' is least recently used
        lru.put("d", "4"); // should evict 'b'
        lru.dump();

        System.out.println("\n=== LFU Cache ===");
        Cache lfu = new Cache(3, new LFUEviction());
        lfu.put("x", "1"); lfu.put("y", "2"); lfu.put("z", "3");
        lfu.get("x"); lfu.get("x"); lfu.get("y"); // x=3, y=2, z=1
        lfu.put("w", "4"); // should evict 'z' (freq=1)
        lfu.dump();

        System.out.println("\n=== FIFO Cache ===");
        Cache fifo = new Cache(3, new FIFOEviction());
        fifo.put("p", "1"); fifo.put("q", "2"); fifo.put("r", "3");
        fifo.put("s", "4"); // should evict 'p' (first inserted)
        fifo.dump();
    }
}

