#include <iostream>
#include <string>
#include <unordered_map>
#include <memory>
#include <climits>
#include <set>
using namespace std;

struct CacheEntry { string value; int frequency; int lastAccessed; int insertOrder; };

class EvictionStrategy {
public:
    virtual ~EvictionStrategy() = default;
    virtual string selectEviction(const unordered_map<string, CacheEntry>& entries) = 0;
    virtual string getName() = 0;
};

class LRUEviction : public EvictionStrategy {
public:
    string selectEviction(const unordered_map<string, CacheEntry>& entries) override {
        string key; int minTime = INT_MAX;
        for (const auto& [k, e] : entries)
            if (e.lastAccessed < minTime) { minTime = e.lastAccessed; key = k; }
        return key;
    }
    string getName() override { return "LRU"; }
};

class LFUEviction : public EvictionStrategy {
public:
    string selectEviction(const unordered_map<string, CacheEntry>& entries) override {
        string key; int minFreq = INT_MAX;
        for (const auto& [k, e] : entries)
            if (e.frequency < minFreq) { minFreq = e.frequency; key = k; }
        return key;
    }
    string getName() override { return "LFU"; }
};

class FIFOEviction : public EvictionStrategy {
public:
    string selectEviction(const unordered_map<string, CacheEntry>& entries) override {
        string key; int minOrder = INT_MAX;
        for (const auto& [k, e] : entries)
            if (e.insertOrder < minOrder) { minOrder = e.insertOrder; key = k; }
        return key;
    }
    string getName() override { return "FIFO"; }
};

class Cache {
private:
    int maxSize, clock = 0, insertCounter = 0;
    unordered_map<string, CacheEntry> store;
    unique_ptr<EvictionStrategy> strategy;
public:
    Cache(int size, unique_ptr<EvictionStrategy> s) : maxSize(size), strategy(std::move(s)) {}
    string get(const string& key) {
        if (!store.count(key)) return "MISS";
        store[key].frequency++;
        store[key].lastAccessed = ++clock;
        return store[key].value;
    }
    void put(const string& key, const string& value) {
        if (store.count(key)) { store[key].value = value; return; }
        if ((int)store.size() >= maxSize) {
            string evict = strategy->selectEviction(store);
            cout << "  Evicting '" << evict << "' (" << strategy->getName() << ")" << endl;
            store.erase(evict);
        }
        store[key] = {value, 1, ++clock, ++insertCounter};
    }
    void dump() {
        cout << "  Cache keys:";
        for (const auto& [k, _] : store) cout << " " << k;
        cout << endl;
    }
};

int main() {
