// Strategy Interface
interface EvictionStrategy {
    fun selectEviction(metadata: Map<String, IntArray>): String?
    fun getName(): String
}

// Concrete Strategies
class LRUEviction : EvictionStrategy {
    // metadata: [frequency, lastAccessed, insertOrder]
    override fun selectEviction(metadata: Map<String, IntArray>) =
        metadata.minByOrNull { it.value[1] }?.key
    override fun getName() = "LRU"
}

class LFUEviction : EvictionStrategy {
    override fun selectEviction(metadata: Map<String, IntArray>) =
        metadata.minByOrNull { it.value[0] }?.key
    override fun getName() = "LFU"
}

class FIFOEviction : EvictionStrategy {
    override fun selectEviction(metadata: Map<String, IntArray>) =
        metadata.minByOrNull { it.value[2] }?.key
    override fun getName() = "FIFO"
}

// Context
class Cache(
    private val maxSize: Int,
    private val strategy: EvictionStrategy
) {
    private val store = mutableMapOf<String, String>()
    // metadata: [frequency, lastAccessed, insertOrder]
    private val metadata = mutableMapOf<String, IntArray>()
    private var clock = 0
    private var insertCounter = 0

    fun get(key: String): String {
        if (key !in store) return "MISS"
        metadata[key]?.let { it[0]++; it[1] = ++clock }
        return store[key]!!
    }

    fun put(key: String, value: String) {
        if (key in store) { store[key] = value; return }
        if (store.size >= maxSize) {
            val evict = strategy.selectEviction(metadata)
            if (evict != null) {
                println("  Evicting '$evict' (${strategy.getName()})")
                store.remove(evict)
                metadata.remove(evict)
            }
        }
        store[key] = value
        metadata[key] = intArrayOf(1, ++clock, ++insertCounter)
    }

    fun dump() = println("  Cache keys: ${store.keys}")
}

fun main() {
    println("=== LRU Cache ===")
    val lru = Cache(3, LRUEviction())
    lru.put("a", "1"); lru.put("b", "2"); lru.put("c", "3")
    lru.get("a") // touch 'a' so 'b' is least recently used
    lru.put("d", "4") // should evict 'b'
    lru.dump()

    println("\n=== LFU Cache ===")
    val lfu = Cache(3, LFUEviction())
    lfu.put("x", "1"); lfu.put("y", "2"); lfu.put("z", "3")
    lfu.get("x"); lfu.get("x"); lfu.get("y") // x=3, y=2, z=1
    lfu.put("w", "4") // should evict 'z' (freq=1)
    lfu.dump()

    println("\n=== FIFO Cache ===")
    val fifo = Cache(3, FIFOEviction())
    fifo.put("p", "1"); fifo.put("q", "2"); fifo.put("r", "3")
    fifo.put("s", "4") // should evict 'p' (first inserted)
    fifo.dump()
}
